"use strict";(self.webpackChunkhalt_website=self.webpackChunkhalt_website||[]).push([[22133],{38629:e=>{e.exports=JSON.parse('{"tag":{"label":"dental","permalink":"/docs/tags/dental","allTagsPath":"/docs/tags","count":3,"items":[{"id":"guinea-pigs/health-and-wellness/dental-disease","title":"Dental Disease in Guinea Pigs","description":"Dental disease is one of the most common and serious health problems affecting guinea pigs. Unlike humans, a guinea pig\'s teeth grow continuously throughout their life. This continuous growth can...","permalink":"/docs/guinea-pigs/health-and-wellness/dental-disease"},{"id":"Rabbits/health-and-wellness/home-health-care-for-your-rabbit","title":"Home Health Care for Your Rabbit","description":"Caring for a rabbit can be a deeply rewarding experience, bringing joy and companionship to your home. These intelligent and social creatures, capable of living up to 12\u201315 years, thrive with proper care and attention [1]. Understanding their unique needs \u2014 from diet to dental health and disease prevention \u2014 is crucial for ensuring a long and happy life for your furry friend. This guide walks you through essential aspects of home health care for your rabbit.","permalink":"/docs/Rabbits/health-and-wellness/home-health-care-for-your-rabbit"},{"id":"Rats/health-and-wellness/rat-dental-care","title":"Rat Dental Care Guide","description":"Dental health is one of the most important \u2014 and most overlooked \u2014 aspects of rat care. Because rat incisors grow continuously throughout life, they must wear down properly to prevent serious complications. A rat with dental problems will struggle to eat, lose weight rapidly, and can deteriorate quickly. Understanding how rat teeth work and how to support healthy dental wear is essential for every rat owner.","permalink":"/docs/Rats/health-and-wellness/rat-dental-care"}],"unlisted":false}}')}}]);